**Algorithm O(n):** Har index i pe prefix sum P[i]. Hum chahte hain pairs (j, i) jahan P[i] - P[j] = T, yaani P[j] = P[i] - T. Map mein har prefix sum ki frequency rakho.

```js
function countSumWindows(scores, T) {
  const freq = new Map();
  freq.set(0, 1); // empty prefix
  let sum = 0, count = 0;
  for (const v of scores) {
    sum += v;
    if (freq.has(sum - T)) count += freq.get(sum - T);
    freq.set(sum, (freq.get(sum) || 0) + 1);
  }
  return count;
}
